import React from "react";
import "./MainContent.scss";
import { Switch, Route, useLocation, useHistory } from "react-router-dom";
import routes from "../../routers/routers";
import routeKey from "../../constants/routeKeys";


export default () => {
  const { pathname } = useLocation();
  const histroy = useHistory();
  const mainContentRoutes = routes.find(r => r.routeKey === routeKey.mainContent);

  if (pathname === "/") {
    histroy.push("/about");
  }

  return (
    <div className="main-content">
      {(mainContentRoutes && mainContentRoutes.routes) &&
        <Switch>
          {mainContentRoutes.routes.map(r => (
            <Route
              key={r.routeKey}
              path={r.path}
              component={r.component}
              exact={r.exact}
            />)
          )}
        </Switch>
      }

    </div>
  )
}