import { AnyAction } from "redux";
import routeKeys from "../../constants/routeKeys";
import { ChangeActiveTag, CHANGE_ACTIVE_TAG } from "../actions/app.action";
import { TAppState } from "../models/app.state";

const initialState: TAppState = {
  activeTag: "about"
}

export default (state: TAppState = initialState, action: AnyAction): TAppState => {
  switch (action.type) {
    case CHANGE_ACTIVE_TAG: {
      const { activeTag } = (action as ChangeActiveTag).payload;
      return { ...state, activeTag }
    }
    default:
      return state;
  }
}