import MainContent from "../components/common/MainContent";
import About from "../components/pages/About";
import Skills from "../components/pages/Skills";
import Contact from "../components/pages/Contact";
import Portfolio from "../components/pages/Portfolio";
import Experience from "../components/pages/Experience";
import Blog from "../components/pages/Blog";
import routeKey from "../constants/routeKeys";
import navigations from "../constants/navigations";

interface IRouter {
  routeKey: string,
  path: string,
  component: () => JSX.Element,
  exact?: boolean,
  routes?: IRouter[]
}

const routers: IRouter[] = [
  {
    routeKey: routeKey.mainContent,
    path: "/",
    component: MainContent,
    routes: [
      {
        routeKey: routeKey.about,
        path: navigations.ABOUT,
        component: About,
        exact: true
      },
      {
        routeKey: routeKey.skills,
        path: navigations.SKILLS,
        component: Skills,
        exact: true
      },
      {
        routeKey: routeKey.portfolio,
        path: navigations.PORTFOLIO,
        component: Portfolio,
        exact: true
      },
      {
        routeKey: routeKey.experience,
        path: navigations.EXPERIENCE,
        component: Experience,
        exact: true
      },
      {
        routeKey: routeKey.blog,
        path: navigations.BLOG,
        component: Blog,
        exact: true
      },
      {
        routeKey: routeKey.contact,
        path: navigations.CONTACT,
        component: Contact,
        exact: true
      },
    ]
  }
]

export default routers;