
import React, { ReactNode } from "react"
import "./Circular.scss";

export default ({ height, children }: { height: number, children: ReactNode }) => {
  return (
    <div style={{
      width: height,
      height,
      borderRadius: "50%",
      overflow: "hidden",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",

    }}
      className="circular"
    >
      {children}
    </div>
  )
}